import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

public class Main {
    static final int MAXN = 13;
    static final int MAXMASK = (1 << MAXN);
    static int N, K;
    static int[] X = new int[MAXN];
    static int[] Y = new int[MAXN];
    static double[] width = new double[MAXMASK];
    static int[] popcnt = new int[MAXMASK];

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            N = Integer.parseInt(st.nextToken());
            K = Integer.parseInt(st.nextToken());
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                X[i] = Integer.parseInt(st.nextToken());
                Y[i] = Integer.parseInt(st.nextToken());
            }
            double min_max_distance = Double.MAX_VALUE;
            for (int mask = 0; mask < MAXMASK; mask++) {
                if (Integer.bitCount(mask) == K) {
                    double max_distance = 0;
                    for (int i = 0; i < N; i++) {
                        double min_distance = Double.MAX_VALUE;
                        for (int j = 0; j < N; j++) {
                            if ((mask & (1 << j)) != 0) {
                                double A = Y[j] - Y[i];
                                double B = X[i] - X[j];
                                double C = X[j] * Y[i] - X[i] * Y[j];
                                double distance = Math.abs(A * X[i] + B * Y[i] + C) / Math.sqrt(A * A + B * B);
                                min_distance = Math.min(min_distance, distance);
                            }
                        }
                        max_distance = Math.max(max_distance, min_distance);
                    }
                    min_max_distance = Math.min(min_max_distance, max_distance);
                }
            }
            System.out.printf("%.6f\n", min_max_distance);
        }
    }
}

